post.content:
How to solve the throttled scenario? Ie, if maxCount = 3, the 4th progress bar will start only when the first is finished?
I have the solution for starting the Nth bar only when the N-1th is finished.

https://jsfiddle.net/sarathsnair/oxLc7pre/

HTML
```
<button id="addBtn">add+</button>
<div class="progress" style="display:none">
  <div class="bar"></div>
</div>
```

CSS
```
.progress {
  height: 20px;
  border: 1px solid;
  width: 500px;
  margin: 20px 0;
  background-color: grey;
  border-radius: 5px;
}

.bar {
  width: 0px;
  height: 100%;
  background-color: red;
  transition: width 2s ease-in 0s;
}

.loading{
  width: 100%;
}
```

JavaScript
```
let btn = document.querySelector('button');
let progressBar = document.querySelector('.progress')
let promise = Promise.resolve();
btn.addEventListener('click', () => {

  let clonedProgress = progressBar.cloneNode(true);
  clonedProgress.style.display = 'block';

  promise = promise.then(() => new Promise((resolve) => {
    setTimeout(() => {
      clonedProgress.querySelector('.bar').classList.add('loading')
      setTimeout(() => {
      	resolve();
      },2000)
    }, 0)
  }))
  document.body.appendChild(clonedProgress)
})

```

SOLUTION#1
```
function throttleBy(fn, timeInterval, maxActive) {
        let isAlreadyRunning = false;
        let queueSize = 0;
        return function () {
            queueSize++;
            if (isAlreadyRunning) return;
            isAlreadyRunning = queueSize === maxActive;
            processQ();

            function processQ() {
                fn();
                setTimeout(() => {
                    queueSize--;
                    isAlreadyRunning = queueSize >= maxActive;
                    if (queueSize) {
                        processQ();
                    }
                }, timeInterval)
            }
        }
    }
```

SOLUTION#2

https://jsfiddle.net/1vf4hm9z/2/

HTML
```
<template id="progress-bar-template">
  <div class="progress-outer">
    <div class="progress-inner">
    </div>
  </div>
</template>

<div class="container">
</div>
<div>
  <input id="btnAddMore" type="button" value="Add Progress Bar">
</div>
```

CSS
```
.progress-outer {
  width: 200px;
  height: 15px;
  background-color: lightgray;
  margin-bottom: 10px;
}

.progress-inner {
  height: 100%;
  background-color: green;
  width: 0;
}

.active {
  animation-name: progress;
  animation-duration: 3s;
  animation-fill-mode: forwards;
}

@keyframes progress {
  0% {
    width: 0;
  }

  100% {
    width: 100%;
  }
}
```

Javascript
```
function addProgress() {
  const progressTemplate = document.getElementById("progress-bar-template").content.cloneNode(true);
  const inner = progressTemplate.querySelector(".progress-inner");
  document.querySelector(".container").append(progressTemplate)
  return inner;
}

const queue = [];

document.getElementById("btnAddMore").addEventListener("click", () => {
  queue.push(addProgress());
  startProcess();
})

let isAlreadyRunning = false;

function startProcess() {
  if (isAlreadyRunning)
    return

  isAlreadyRunning = queue.length >= 3;
  processQ();

  function processQ() {
    const next = document.querySelector(".progress-inner:not(.active)")
    next.classList.add("active");

    setTimeout(() => {
      queue.shift()
      isAlreadyRunning = queue.length >= 3;
      if (queue.length >= 3) {
        processQ()
      }
    }, 3000)
  }
}
```
